scwin.udc_vehcl_onclickEvent = function (e) {
  scwin.f_openCommonPopUp(1, txt_vehclShortCd.getValue(), txt_vehclNos.getValue(), 'F', 'F');
};
scwin.f_reflashdata = function () {
  let parentWin = $p.parent();
  if (parentWin && parentWin.scwin && typeof parentWin.scwin.reflashdata === "function") {
    parentWin.scwin.reflashdata();
  }
};
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
  // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  if (!$c.gus.cfCanOpenPopup($p, inObj, pairObj)) return;

  // 짝이 되는 오브젝트의 값 제거
  //    $c.gus.cfClearPairObj(pairObj);

  // 검색어 세팅
  var pVal = $c.gus.cfGetValue($p, inObj);

  // inObj가 코드 필드일 경우 팝업
  if (isCode == null || isCode == true) scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
  // inObj가 코드명 필드일 경우 팝업
  else scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
