scwin.vehclStsExp = function (data, formatData, rowIdx, colIdx) {
  if (data == "대기(0)") {
    if (tac_car.getSelectedTabIndex() == 0) {
      gr_car.setCellStyle(rowIdx, colIdx, "color", "blue");
    } else if (tac_car.getSelectedTabIndex() == 1) {
      gr_car_blk.setCellStyle(rowIdx, colIdx, "color", "blue");
    } else if (tac_car.getSelectedTabIndex() == 2) {
      gr_car_cntr.setCellStyle(rowIdx, colIdx, "color", "blue");
    } else if (tac_car.getSelectedTabIndex() == 3) {
      gr_car_mb.setCellStyle(rowIdx, colIdx, "color", "blue");
    }
  } else if (data == "종료") {
    if (tac_car.getSelectedTabIndex() == 0) {
      gr_car.setCellStyle(rowIdx, colIdx, "color", "black");
    } else if (tac_car.getSelectedTabIndex() == 1) {
      gr_car_blk.setCellStyle(rowIdx, colIdx, "color", "black");
    } else if (tac_car.getSelectedTabIndex() == 2) {
      gr_car_cntr.setCellStyle(rowIdx, colIdx, "color", "black");
    } else if (tac_car.getSelectedTabIndex() == 3) {
      gr_car_mb.setCellStyle(rowIdx, colIdx, "color", "black");
    }
  } else {
    if (tac_car.getSelectedTabIndex() == 0) {
      gr_car.setCellStyle(rowIdx, colIdx, "color", "red");
    } else if (tac_car.getSelectedTabIndex() == 1) {
      gr_car_blk.setCellStyle(rowIdx, colIdx, "color", "red");
    } else if (tac_car.getSelectedTabIndex() == 2) {
      gr_car_cntr.setCellStyle(rowIdx, colIdx, "color", "red");
    } else if (tac_car.getSelectedTabIndex() == 3) {
      gr_car_mb.setCellStyle(rowIdx, colIdx, "color", "red");
    }
  }
  return data;
};
