scwin.checkSub = async function (idx) {
  let vFlType = "";
  let idxs = idx.split("-");
  let cars = "";
  let vehclTypeVal = $p.parent().wfm_wframe1.getWindow().scwin.vehclType;
  switch (vehclTypeVal) {
    case 'all':
      for (let nRCnt = 0; nRCnt < dtl_car.getRowCount(); nRCnt++) {
        //                if (dtl_car.getRowMark(nRCnt)) {
        cars += dtl_car.getCellData(nRCnt, "ez110Idx") + ',';
        //                }
      }
      break;
    case 'blk':
      for (let nRCnt = 0; nRCnt < dtl_car_blk.getRowCount(); nRCnt++) {
        //                if (dtl_car_blk.getRowMark(nRCnt)) {
        cars += ds_car_blk.getCellData(nRCnt, "ez110Idx") + ',';
        //                }
      }
      break;
    case 'cntr':
      for (let nRCnt = 0; nRCnt < dtl_car_cntr.getRowCount(); nRCnt++) {
        //                if (ds_car_cntr.getRowMark(nRCnt)) {
        cars += dtl_car_cntr.getCellData(nRCnt, "ez110Idx") + ',';
        //                }
      }
      break;
    case 'matching':
      for (let nRCnt = 0; nRCnt < dtl_car_matching.getRowCount(); nRCnt++) {
        //                if (dtl_car_matching.getRowMark(nRCnt)) {
        cars += dtl_car_matching.getCellData(nRCnt, "ez110Idx") + ',';
        //                }
      }
      break;
    case 'mb':
      for (let nRCnt = 0; nRCnt < dtl_car_mb.getRowCount(); nRCnt++) {
        //                    if (ds_car_mb.getRowMark(nRCnt)) {
        cars += dtl_car_mb.getCellData(nRCnt, "ez110Idx") + ',';
        //                    }
      }
      break;
    case 'tab6':
      for (let nRCnt = 0; nRCnt < dtl_openPublic.getRowCount(); nRCnt++) {
        //                if (ds_openPublic.getRowMark(nRCnt)) {
        cars += dtl_openPublic.getCellData(nRCnt, "ez110Idx") + ',';
        //              }
      }
      break;
  }
  if ($p.parent().wfm_wframe1.getWindow().tac_bulkCont.getSelectedTabIndex() == 0) {
    vFlType = "1";
  } else {
    vFlType = "2";
  }
  cars = cars.substring(0, cars.length - 1);
  cars = cars.split(",");
  dtl_car_allocar_sub.setData([]);
  for (let i = 0; i < cars.length; i++) {
    let newRow = dtl_car_allocar_sub.insertRow();
    dtl_car_allocar_sub.setCellData(newRow, "flType", vFlType);
    dtl_car_allocar_sub.setCellData(newRow, "flMasterIdx", idxs[0]);
    dtl_car_allocar_sub.setCellData(newRow, "flDetailIdx", idxs[1]);
    dtl_car_allocar_sub.setCellData(newRow, "flCarIdx", cars[i]);
  }
  await $c.sbm.execute($p, sbm_car_allocar_sub);
};

